"""Загрузка и сохранение config.json проекта. Формат: project, discovery, extract, image_processing, markdown, pipeline."""from __future__ import annotationsimport jsonfrom pathlib import Pathfrom typing import Anyfrom src.modules.file_extract import normalize_extract_payloadfrom .project_config import PROJECT_CONFIG_KEYS, ProjectConfigfrom .project_paths import ProjectPathsfrom .sections import (    DiscoveryConfig,    ExtractConfig,    ImageProcessingConfig,    MarkdownConfig,    PipelineConfig,    TaggingConfig,)def ensure_project_dirs(project_root: Path) -> None:    """Создаёт docs, cache, result, logs внутри проекта при необходимости."""    for name in ("docs", "cache", "result", "logs"):        (project_root / name).mkdir(parents=True, exist_ok=True)def load_project_config(project_root: Path) -> ProjectConfig:    """Загружает config.json (формат: project, discovery, extract, image_processing, pipeline)."""    ensure_project_dirs(project_root)    config_path = project_root / "config.json"    if config_path.exists():        raw = config_path.read_text(encoding="utf-8").strip()        if not raw:            raise ValueError(f"config.json пустой: {config_path}")        try:            data = json.loads(raw)        except json.JSONDecodeError as e:            raise ValueError(f"config.json — невалидный JSON ({config_path}): {e}") from e        if not isinstance(data, dict):            raise ValueError(f"config.json должен быть объектом, получено: {type(data).__name__}")        extract_data = data.get("extract")        if not isinstance(extract_data, dict):            extract_data = ExtractConfig.get_default()        else:            extract_data = normalize_extract_payload(extract_data)        disc_raw = data.get("discovery")        if not isinstance(disc_raw, dict):            discovery = dict(DiscoveryConfig.get_default())        else:            discovery = dict(disc_raw)            discovery["recursive_search"] = bool(discovery.get("recursive_search", False))        ip_raw = data.get("image_processing")        if not isinstance(ip_raw, dict):            image_processing = dict(ImageProcessingConfig.get_default())        else:            defaults = ImageProcessingConfig.get_default()            image_processing = dict(defaults)            for k in defaults:                if k in ip_raw:                    image_processing[k] = ip_raw[k]        md_raw = data.get("markdown")        if not isinstance(md_raw, dict):            markdown = dict(MarkdownConfig.get_default())        else:            defaults = MarkdownConfig.get_default()            markdown = dict(defaults)            for k in defaults:                if k in md_raw:                    markdown[k] = md_raw[k]        tagging_raw = data.get("tagging")        if not isinstance(tagging_raw, dict):            tagging = dict(TaggingConfig.get_default())        else:            defaults = TaggingConfig.get_default()            tagging = dict(defaults)            for k in defaults:                if k in tagging_raw:                    tagging[k] = tagging_raw[k]            tagging = TaggingConfig.with_normalized_bools(tagging)        pl_raw = data.get("pipeline")        if not isinstance(pl_raw, dict):            pipeline = dict(PipelineConfig.get_default())        else:            defaults = PipelineConfig.get_default()            pipeline = dict(defaults)            for k in defaults:                if k in pl_raw:                    pipeline[k] = pl_raw[k]        paths = ProjectPaths.from_root(project_root)        return ProjectConfig(            paths=paths,            discovery=discovery,            extract=dict(extract_data),            image_processing=image_processing,            markdown=markdown,            tagging=tagging,            pipeline=pipeline,        )    return ProjectConfig.create_default(project_root)def save_project_config(project_root: Path, data: dict) -> None:    """Сохраняет config.json (формат: project, discovery, extract, image_processing, pipeline). Неизвестные ключи попадают в project."""    config_path = project_root / "config.json"    project = dict(data.get("project", {}))    for k, v in data.items():        if k not in PROJECT_CONFIG_KEYS:            project[k] = v    payload = {        "project": project,        "discovery": data.get("discovery", DiscoveryConfig.get_default()),        "extract": data.get("extract", ExtractConfig.get_default()),        "image_processing": data.get("image_processing", ImageProcessingConfig.get_default()),        "markdown": data.get("markdown", MarkdownConfig.get_default()),        "tagging": data.get("tagging", TaggingConfig.get_default()),        "pipeline": data.get("pipeline", PipelineConfig.get_default()),    }    with open(config_path, "w", encoding="utf-8") as f:        json.dump(payload, f, ensure_ascii=False, indent=2)def load_project_config_dict(project_root: Path) -> dict:    """Загружает config.json как словарь. При отсутствии/ошибке — дефолт из ProjectConfig.create_default_dict(). По ключам PROJECT_CONFIG_KEYS."""    config_path = project_root / "config.json"    default = ProjectConfig.create_default_dict()    if not config_path.exists():        return dict(default)    raw = config_path.read_text(encoding="utf-8").strip()    if not raw:        return dict(default)    try:        data = json.loads(raw)    except json.JSONDecodeError:        return dict(default)    if not isinstance(data, dict):        return dict(default)    data = dict(data)    for key in PROJECT_CONFIG_KEYS:        if key not in data or not isinstance(data.get(key), dict):            data[key] = default[key] if key in default else {}    data["discovery"] = dict(data["discovery"])    data["discovery"]["recursive_search"] = bool(data["discovery"].get("recursive_search", False))    ip_defaults = ImageProcessingConfig.get_default()    data["image_processing"] = {**ip_defaults, **{k: data["image_processing"][k] for k in ip_defaults if k in data["image_processing"]}}    md_defaults = MarkdownConfig.get_default()    data["markdown"] = {**md_defaults, **{k: data["markdown"][k] for k in md_defaults if k in data["markdown"]}}    if "tagging" not in data or not isinstance(data.get("tagging"), dict):        data["tagging"] = dict(TaggingConfig.get_default())    else:        tag_defaults = TaggingConfig.get_default()        data["tagging"] = TaggingConfig.with_normalized_bools(            {**tag_defaults, **{k: data["tagging"][k] for k in tag_defaults if k in data["tagging"]}}        )    pl_defaults = PipelineConfig.get_default()    data["pipeline"] = {**pl_defaults, **{k: data["pipeline"][k] for k in pl_defaults if k in data["pipeline"]}}    # extract: канонический вид (group-based) через normalize; при отсутствии — ExtractConfig.get_default()    data["extract"] = normalize_extract_payload(data.get("extract"))    return datadef save_project_config_dict(project_root: Path, data: dict) -> None:    """Сохраняет словарь в config.json (формат: project, discovery, extract, image_processing, markdown, pipeline)."""    save_project_config(project_root, data)